mapper.select:
SELECT COUNT(*) FROM word w
LEFT JOIN student_word_mode_progress p ON w.id = p.word_id
  AND p.tenant_id = #{tenantId} AND p.user_id = #{userId} AND p.mode = #{mode}
WHERE w.unit_id = #{unitId}
  AND (p.id IS NULL OR p.consecutive_correct < 2)

SELECT w.id
FROM word w
LEFT JOIN student_word_mode_progress p ON w.id = p.word_id
  AND p.tenant_id = #{tenantId} AND p.user_id = #{userId} AND p.mode = #{mode}
WHERE w.unit_id = #{unitId}
  AND (p.id IS NULL OR p.consecutive_correct < 2)
ORDER BY w.sort_order ASC
LIMIT #{limit}
